import {
  Badge,
  NumberSizeableText,
  PulseContainer,
  SizableText,
  Stack,
  XStack,
  YStack,
} from '@onekeyhq/components';
import type { IStackProps } from '@onekeyhq/components';
import type { IListItemProps } from '@onekeyhq/kit/src/components/ListItem';
import { ListItem } from '@onekeyhq/kit/src/components/ListItem';
import type { IFuseResultMatch } from '@onekeyhq/shared/src/modules3rdParty/fuse';
import accountUtils from '@onekeyhq/shared/src/utils/accountUtils';

import { Token } from '../Token';

export type ITokenListItemProps = {
  tokenImageSrc?: string;
  networkImageSrc?: string;
  tokenName?: string;
  tokenSymbol?: string;
  tokenContrastAddress?: string;
  balance?: string;
  isSearch?: boolean;
  isLoading?: boolean;
  valueProps?: { value: string; currency?: string };
  disabled?: boolean;
  titleMatchStr?: IFuseResultMatch;
  moreComponent?: React.ReactNode;
  tokenSymbolAccessory?: React.ReactNode;
  badgeText?: string;
  tokenSize?: 'xxs' | 'xs' | 'sm' | 'md' | 'lg' | 'xl';
} & IListItemProps &
  IStackProps;

export function TokenListItem({
  tokenImageSrc,
  networkImageSrc,
  tokenName,
  isSearch,
  isLoading,
  tokenSymbol,
  tokenContrastAddress,
  balance,
  valueProps,
  disabled,
  titleMatchStr,
  moreComponent,
  tokenSymbolAccessory,
  badgeText,
  tokenSize,
  ...rest
}: ITokenListItemProps) {
  const primaryContent =
    badgeText || tokenSymbolAccessory ? (
      <XStack alignItems="center" gap="$1" minWidth={0}>
        <SizableText
          size="$bodyLgMedium"
          numberOfLines={1}
          ellipsizeMode="tail"
          flexShrink={1}
        >
          {tokenSymbol}
        </SizableText>
        {badgeText ? (
          <Badge badgeType="success" badgeSize="sm">
            {badgeText}
          </Badge>
        ) : null}
        {tokenSymbolAccessory}
      </XStack>
    ) : (
      tokenSymbol
    );

  return (
    <ListItem
      userSelect="none"
      {...(isSearch && {
        $md: {
          alignItems: 'flex-start',
        },
      })}
      {...rest}
    >
      <YStack
        {...(disabled && {
          opacity: 0.5,
        })}
      >
        <Token
          size={tokenSize}
          tokenImageUri={tokenImageSrc}
          networkImageUri={networkImageSrc}
        />
      </YStack>
      <ListItem.Text
        {...(disabled && {
          opacity: 0.5,
        })}
        flex={1}
        primary={primaryContent}
        primaryMatch={titleMatchStr}
        primaryTextProps={{
          numberOfLines: 1,
        }}
        secondary={
          isSearch ? (
            <Stack gap="$0.5" $gtMd={{ flexDirection: 'row', gap: '$1' }}>
              <SizableText
                numberOfLines={1}
                color="$textSubdued"
                size="$bodyMd"
              >
                {tokenName}
              </SizableText>
              <SizableText color="$textDisabled" size="$bodyMd">
                {accountUtils.shortenAddress({
                  address: tokenContrastAddress,
                  leadingLength: 8,
                  trailingLength: 6,
                })}
              </SizableText>
            </Stack>
          ) : (
            (tokenName ?? '')
          )
        }
      />
      <ListItem.Text
        {...(disabled && {
          opacity: 0.5,
        })}
        align="right"
        primary={
          <PulseContainer isActive={isLoading}>
            <NumberSizeableText
              textAlign="right"
              color="$text"
              formatter="balance"
              size="$bodyLgMedium"
            >
              {balance}
            </NumberSizeableText>
          </PulseContainer>
        }
        secondary={
          <PulseContainer isActive={isLoading}>
            {valueProps?.value ? (
              <NumberSizeableText
                textAlign="right"
                size="$bodyMd"
                formatter="value"
                color="$textSubdued"
                formatterOptions={{ currency: valueProps?.currency ?? '$' }}
              >
                {valueProps.value}
              </NumberSizeableText>
            ) : null}
          </PulseContainer>
        }
      />
      {moreComponent}
    </ListItem>
  );
}
